eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   RESEARCH: () => (/* binding */ RESEARCH)\n/* harmony export */ });\nconst RESEARCH = [\n    {\n        id: \"r1\",\n        date: \"Mar 26\",\n        org: \"Google DeepMind\",\n        lab: \"Google DeepMind\",\n        category: \"reasoning\",\n        tagLabel: \"Reasoning\",\n        tagColor: \"#1E4DA8\",\n        tagBg: \"#EBF0FC\",\n        accentColor: \"#1E4DA8\",\n        title: \"Gemini 2.5 Pro achieves new SOTA on reasoning benchmarks\",\n        summary: \"Scores 83.2% on AIME 2025 math competition, outperforming all prior models on reasoning-intensive tasks.\",\n        abstract: \"Google DeepMind's Gemini 2.5 Pro has set a new state-of-the-art across multiple reasoning benchmarks, most notably scoring 83.2% on the highly competitive AIME 2025 mathematical competition. This result surpasses GPT-5, Claude Opus 4.6, and all prior frontier models on reasoning-intensive evaluations. The paper introduces a novel chain-of-thought extension called 'Iterative Thought Refinement' (ITR), which enables the model to backtrack and revise intermediate reasoning steps in real-time, dramatically improving accuracy on multi-step logical and mathematical problems.\",\n        stats: [\n            {\n                v: \"83.2%\",\n                l: \"AIME 2025 score\"\n            },\n            {\n                v: \"+6.4%\",\n                l: \"vs prior SOTA\"\n            },\n            {\n                v: \"5M ctx\",\n                l: \"Context window\"\n            }\n        ],\n        findings: [\n            \"New Iterative Thought Refinement (ITR) allows real-time reasoning backtracking, boosting math accuracy by 18% vs standard CoT.\",\n            \"Gemini 2.5 Pro scored top-1 on MATH, HumanEval, and MMLU-Pro simultaneously — a first for any single model.\",\n            \"Performance gains are most significant on problems requiring 10+ reasoning steps, suggesting ITR scales with complexity.\",\n            \"Multimodal reasoning (diagrams + equations) also improved 22% over Gemini 2.0, crucial for physics and geometry tasks.\"\n        ],\n        models: [\n            \"Gemini 2.5 Pro\",\n            \"GPT-5\",\n            \"Claude Opus 4.6\",\n            \"o3\"\n        ],\n        authors: \"Anil, R., Borgeaud, S., Wu, Y., et al. — Google DeepMind\",\n        published: \"March 26, 2026\",\n        arxiv: \"arXiv:2603.08821\",\n        impact: \"High — sets new benchmark baseline for all future frontier model evaluations.\",\n        discussPrompt: \"Explain how Gemini 2.5 Pro achieves 83.2% on AIME 2025 and what Iterative Thought Refinement means for reasoning AI\"\n    },\n    {\n        id: \"r2\",\n        date: \"Mar 22\",\n        org: \"MIT CSAIL\",\n        lab: \"MIT CSAIL\",\n        category: \"multimodal\",\n        tagLabel: \"Multimodal\",\n        tagColor: \"#0A5E49\",\n        tagBg: \"#E2F5EF\",\n        accentColor: \"#0A5E49\",\n        title: \"Scaling laws for multimodal models: new empirical findings\",\n        summary: \"Research reveals unexpected scaling dynamics when combining vision and language — efficiency gains plateau earlier than expected.\",\n        abstract: 'MIT CSAIL researchers present a comprehensive empirical study of scaling laws specifically for multimodal large language models (MLLMs). Contrary to prior assumptions derived from unimodal language models, the team finds that combining vision and language encoders introduces cross-modal interference at scale, causing compute efficiency gains to plateau around 70B–100B parameter range — far earlier than for text-only models. The paper proposes a novel \"Modal Decoupled Scaling\" (MDS) strategy that alleviates this bottleneck.',\n        stats: [\n            {\n                v: \"70-100B\",\n                l: \"Plateau point\"\n            },\n            {\n                v: \"31%\",\n                l: \"Efficiency gap\"\n            },\n            {\n                v: \"12 models\",\n                l: \"Benchmarked\"\n            }\n        ],\n        findings: [\n            \"Vision-language efficiency plateau occurs ~3x earlier than in text-only models, suggesting current scaling recipes need revision.\",\n            \"Modal Decoupled Scaling (MDS) recovers ~31% of lost efficiency by training modalities on separate optimizers before fusion.\",\n            \"Cross-modal interference is highest in mid-layers (layers 12–24), pointing to specific architectural interventions.\",\n            \"Open-source models (Llama 4, Qwen VL) show faster plateau than proprietary models, likely due to training data composition.\"\n        ],\n        models: [\n            \"Gemini 3.1 Pro\",\n            \"GPT-5\",\n            \"Llama 4 Maverick\",\n            \"Qwen3-Max\"\n        ],\n        authors: \"Chen, K., Goldwasser, D., Barzilay, R., et al. — MIT CSAIL\",\n        published: \"March 22, 2026\",\n        arxiv: \"arXiv:2603.05512\",\n        impact: \"Medium-High — directly challenges current scaling assumptions for multimodal AI.\",\n        discussPrompt: \"Explain the MIT CSAIL scaling law findings for multimodal models and what Modal Decoupled Scaling means in practice\"\n    },\n    {\n        id: \"r3\",\n        date: \"Mar 18\",\n        org: \"Anthropic\",\n        lab: \"Anthropic\",\n        category: \"alignment\",\n        tagLabel: \"Alignment\",\n        tagColor: \"#C8622A\",\n        tagBg: \"#FDF1EB\",\n        accentColor: \"#C8622A\",\n        title: \"Constitutional AI v2: improved alignment through iterative refinement\",\n        summary: \"New methodology achieves 40% reduction in harmful outputs while preserving capability on standard benchmarks.\",\n        abstract: 'Anthropic introduces Constitutional AI v2 (CAI-2), a significantly improved alignment framework that builds on the original CAI approach. The key innovation is \"Iterative Constitutional Refinement\" (ICR), where the constitution itself is treated as a learnable document that evolves through multiple rounds of red-teaming, model critique, and human feedback. CAI-2 achieves a 40% reduction in harmful output rate across Anthropic\\'s evaluation suite while maintaining performance within 0.5% on standard capability benchmarks.',\n        stats: [\n            {\n                v: \"-40%\",\n                l: \"Harmful outputs\"\n            },\n            {\n                v: \"<0.5%\",\n                l: \"Capability drop\"\n            },\n            {\n                v: \"v2.0\",\n                l: \"Constitution ver.\"\n            }\n        ],\n        findings: [\n            \"Iterative Constitutional Refinement (ICR) allows the safety constitution to self-improve via model feedback loops over 5 iterations.\",\n            \"40% reduction in harmful outputs across Anthropic's internal suite with less than 0.5% degradation on MMLU, HumanEval, and MATH.\",\n            \"CAI-2 shows stronger generalisation to novel harmful prompt categories not seen during training — a key improvement over v1.\",\n            \"The approach is model-agnostic and was validated on both Claude Opus 4.6 and smaller Claude Haiku variants.\"\n        ],\n        models: [\n            \"Claude Opus 4.6\",\n            \"Claude Haiku 4.5\",\n            \"Claude Sonnet 4.6\"\n        ],\n        authors: \"Bai, Y., Jones, A., Ndousse, K., et al. — Anthropic\",\n        published: \"March 18, 2026\",\n        arxiv: \"arXiv:2603.03142\",\n        impact: \"High — directly shapes Claude's alignment methodology; influences industry safety standards.\",\n        discussPrompt: \"Explain Constitutional AI v2 from Anthropic and how Iterative Constitutional Refinement reduces harmful outputs while preserving capability\"\n    },\n    {\n        id: \"r4\",\n        date: \"Mar 15\",\n        org: \"Meta AI\",\n        lab: \"Meta AI\",\n        category: \"openweights\",\n        tagLabel: \"Open Weights\",\n        tagColor: \"#1E4DA8\",\n        tagBg: \"#EBF0FC\",\n        accentColor: \"#5A35CC\",\n        title: \"Llama 4 Scout & Maverick: natively multimodal from the ground up\",\n        summary: \"17B MoE architecture trained on 40 trillion tokens with native understanding across text, image, and video.\",\n        abstract: \"Meta AI releases Llama 4 Scout and Llama 4 Maverick, two groundbreaking open-weight models built with Mixture-of-Experts (MoE) architecture natively supporting text, image, and video from pretraining — not added post-hoc via adapters. Scout is the efficient variant (17B active params, 109B total) designed for long-context retrieval, while Maverick is the powerful variant (400B MoE) excelling at complex reasoning and multilingual tasks across 119 languages.\",\n        stats: [\n            {\n                v: \"400B\",\n                l: \"Maverick params\"\n            },\n            {\n                v: \"119\",\n                l: \"Languages\"\n            },\n            {\n                v: \"40T\",\n                l: \"Training tokens\"\n            }\n        ],\n        findings: [\n            \"Native multimodal pretraining (not adapters) allows Scout and Maverick to reason across text, images, and video in a unified token space.\",\n            \"Llama 4 Maverick matches GPT-4o and Claude Sonnet 4.6 on MMLU-Pro while being fully self-hostable — a first for open weights at this capability level.\",\n            \"Scout's 128K context and efficient MoE architecture make it ideal for RAG pipelines and long-document summarisation at low compute cost.\",\n            \"Both models support 119 languages, with particularly strong results in Arabic, Hindi, and Southeast Asian languages vs prior Llama generations.\"\n        ],\n        models: [\n            \"Llama 4 Maverick\",\n            \"Llama 4 Scout\",\n            \"GPT-4o\",\n            \"Claude Sonnet 4.6\"\n        ],\n        authors: \"Dubey, A., Jauhri, A., Pandey, A., et al. — Meta AI\",\n        published: \"March 15, 2026\",\n        arxiv: \"arXiv:2603.01234\",\n        impact: \"Very High — redefines what open-weight models can achieve; major competitive pressure on proprietary labs.\",\n        discussPrompt: \"Explain Llama 4 Scout and Maverick's native multimodal architecture and how they compare to GPT-4o and Claude in practical use\"\n    },\n    {\n        id: \"r5\",\n        date: \"Mar 10\",\n        org: \"Stanford NLP\",\n        lab: \"Stanford NLP\",\n        category: \"efficiency\",\n        tagLabel: \"Efficiency\",\n        tagColor: \"#8A5A00\",\n        tagBg: \"#FDF5E0\",\n        accentColor: \"#8A5A00\",\n        title: \"Long-context recall: how models handle 1M+ token windows\",\n        summary: \"Comprehensive evaluation shows sharp recall degradation beyond 200K tokens for most models tested.\",\n        abstract: 'Stanford NLP\\'s \"LongBench-2026\" study presents the most comprehensive evaluation to date of long-context recall across 14 frontier models, testing windows from 32K to 2M tokens. The key finding is that most models — including GPT-5, Gemini 3.1 Pro, and Claude Opus 4.6 — show sharp recall degradation beyond 200K tokens, with average accuracy dropping from 91% (within 100K tokens) to 58% (at 500K tokens) and just 34% at 1M+ tokens.',\n        stats: [\n            {\n                v: \"34%\",\n                l: \"Recall at 1M tok\"\n            },\n            {\n                v: \"91%\",\n                l: \"Recall at 100K\"\n            },\n            {\n                v: \"14\",\n                l: \"Models tested\"\n            }\n        ],\n        findings: [\n            \"Across all 14 models, recall drops from 91% (100K tokens) to 58% (500K tokens) — a steeper cliff than previously reported.\",\n            \"Kimi-k2.5 and GLM-5 are the top performers at 1M+ token contexts (72% and 68% recall respectively), benefiting from sparse attention innovations.\",\n            'The \"lost in the middle\" phenomenon intensifies at scale: information in the middle 60% of a 1M-token context is recalled at just 28%.',\n            \"Instruction-following capability degrades even faster than information recall — models forget formatting instructions embedded in long contexts.\"\n        ],\n        models: [\n            \"Kimi-k2.5\",\n            \"GPT-5\",\n            \"Claude Opus 4.6\",\n            \"Gemini 3.1 Pro\"\n        ],\n        authors: \"Liu, N., Lin, K., Hewitt, J., et al. — Stanford NLP\",\n        published: \"March 10, 2026\",\n        arxiv: \"arXiv:2603.00187\",\n        impact: \"High — essential reading for teams building RAG or long-document AI applications.\",\n        discussPrompt: \"Explain the Stanford NLP long-context recall findings and what they mean for building RAG applications or document analysis tools\"\n    },\n    {\n        id: \"r6\",\n        date: \"Mar 5\",\n        org: \"DeepSeek\",\n        lab: \"DeepSeek AI\",\n        category: \"openweights\",\n        tagLabel: \"Open Weights\",\n        tagColor: \"#1E4DA8\",\n        tagBg: \"#EBF0FC\",\n        accentColor: \"#2E9E5B\",\n        title: \"DeepSeek-V3.2: sparse attention for cheaper long-context inference\",\n        summary: \"New Sparse Attention mechanism reduces inference costs by 60% at 128K+ context without accuracy loss.\",\n        abstract: \"DeepSeek introduces V3.2, an enhanced version of their MoE architecture featuring a novel Sparse Attention mechanism that selectively computes attention only on the most relevant token subsets. This reduces the memory and compute overhead at 128K+ context windows by 60%, making long-context inference economically viable for enterprise deployments without meaningful accuracy degradation on standard benchmarks.\",\n        stats: [\n            {\n                v: \"-60%\",\n                l: \"Inference cost\"\n            },\n            {\n                v: \"164K\",\n                l: \"Max context\"\n            },\n            {\n                v: \"<1%\",\n                l: \"Accuracy drop\"\n            }\n        ],\n        findings: [\n            \"Sparse Attention selects the most informative token subsets per layer, reducing FLOPS by 60% at 128K context.\",\n            \"Accuracy within 1% of dense attention on MMLU, HumanEval, and GSM8K — essentially no quality tradeoff.\",\n            \"Memory footprint reduced by 45% at 128K context, enabling larger batch sizes and higher throughput on A100/H100.\",\n            \"The technique is architecture-agnostic and can be applied post-hoc to most transformer-based models.\"\n        ],\n        models: [\n            \"DeepSeek-V3.2\",\n            \"DeepSeek-V3\",\n            \"GPT-5\",\n            \"Claude Sonnet 4.6\"\n        ],\n        authors: \"Liu, A., Feng, B., Xue, B., et al. — DeepSeek AI\",\n        published: \"March 5, 2026\",\n        arxiv: \"arXiv:2602.14892\",\n        impact: \"Medium-High — could make 100K+ context models accessible for cost-sensitive deployments.\",\n        discussPrompt: \"Explain DeepSeek-V3.2's Sparse Attention mechanism and how it reduces long-context inference costs without hurting accuracy\"\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/research.ts\n");

